+/**
+ * Webhook notification handler — dispatches HTTP callbacks
+ * when order events occur.
+ *
+ * Integrates with the EventBus pattern used throughout the application.
+ * Subscribes to order lifecycle events and fires registered webhooks.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving order events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { EventType, AppEvent, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookRegistration {
+  id: string;
+  url: string;
+  eventType: EventType;
+  secret?: string;
+  createdAt: Date;
+}
+
+export interface WebhookDelivery {
+  id: string;
+  webhookId: string;
+  url: string;
+  eventType: EventType;
+  payload: WebhookPayload;
+  success: boolean;
+  statusCode?: number;
+  error?: string;
+  deliveredAt: Date;
+}
+
+export interface WebhookPayload {
+  eventType: EventType;
+  timestamp: string;
+  data: Record<string, unknown>;
+}
+
+export type HttpPostFn = (url: string, payload: WebhookPayload, secret?: string) => Promise<{ success: boolean; statusCode?: number; error?: string }>;
+
+let nextWebhookId = 1;
+let nextDeliveryId = 1;
+
+function generateWebhookId(): string {
+  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
+}
+
+function generateDeliveryId(): string {
+  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
+}
+
+export function resetWebhookIdCounters(): void {
+  nextWebhookId = 1;
+  nextDeliveryId = 1;
+}
+
+/**
+ * Default HTTP post function — in-memory stub for demo purposes.
+ * In production, this would use fetch/axios to make real HTTP calls.
+ */
+const defaultHttpPost: HttpPostFn = async () => {
+  return { success: true, statusCode: 200 };
+};
+
+export class WebhookNotificationHandler {
+  private logger = new Logger('WebhookNotificationHandler');
+  private registrations: WebhookRegistration[] = [];
+  private deliveries: WebhookDelivery[] = [];
+  private httpPost: HttpPostFn;
+
+  constructor(private eventBus: EventBus, httpPost?: HttpPostFn) {
+    this.httpPost = httpPost ?? defaultHttpPost;
+    this.registerHandlers();
+  }
+
+  private registerHandlers(): void {
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      return this.dispatchWebhooks(event);
+    });
+
+    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      return this.dispatchWebhooks(event);
+    });
+  }
+
+  /**
+   * Register a webhook URL for a specific event type.
+   */
+  register(url: string, eventType: EventType, secret?: string): WebhookRegistration {
+    const registration: WebhookRegistration = {
+      id: generateWebhookId(),
+      url,
+      eventType,
+      secret,
+      createdAt: new Date(),
+    };
+    this.registrations.push(registration);
+    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
+    return registration;
+  }
+
+  /**
+   * Unregister a webhook by ID.
+   */
+  unregister(webhookId: string): boolean {
+    const index = this.registrations.findIndex((r) => r.id === webhookId);
+    if (index >= 0) {
+      this.registrations.splice(index, 1);
+      this.logger.info(`Webhook unregistered: ${webhookId}`);
+      return true;
+    }
+    return false;
+  }
+
+  /**
+   * Get all registered webhooks.
+   */
+  getRegistrations(): WebhookRegistration[] {
+    return [...this.registrations];
+  }
+
+  /**
+   * Get registrations for a specific event type.
+   */
+  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
+    return this.registrations.filter((r) => r.eventType === eventType);
+  }
+
+  /**
+   * Dispatch webhooks for a given event to all matching registrations.
+   */
+  private async dispatchWebhooks(event: AppEvent): Promise<void> {
+    const matching = this.registrations.filter((r) => r.eventType === event.type);
+
+    if (matching.length === 0) {
+      return;
+    }
+
+    const payload = this.buildPayload(event);
+
+    for (const registration of matching) {
+      await this.deliverWebhook(registration, payload);
+    }
+  }
+
+  private buildPayload(event: AppEvent): WebhookPayload {
+    const base = {
+      eventType: event.type,
+      timestamp: event.timestamp.toISOString(),
+    };
+
+    switch (event.type) {
+      case 'order:created':
+        return {
+          ...base,
+          data: {
+            order: event.order,
+            user: { id: event.user.id, name: event.user.name, email: event.user.email },
+          },
+        };
+      case 'order:status-changed':
+        return {
+          ...base,
+          data: {
+            order: event.order,
+            previousStatus: event.previousStatus,
+            newStatus: event.newStatus,
+          },
+        };
+      default:
+        return { ...base, data: {} };
+    }
+  }
+
+  private async deliverWebhook(registration: WebhookRegistration, payload: WebhookPayload): Promise<void> {
+    this.logger.info(`Delivering webhook ${registration.id} to ${registration.url}`);
+
+    const result = await this.httpPost(registration.url, payload, registration.secret);
+
+    const delivery: WebhookDelivery = {
+      id: generateDeliveryId(),
+      webhookId: registration.id,
+      url: registration.url,
+      eventType: payload.eventType,
+      payload,
+      success: result.success,
+      statusCode: result.statusCode,
+      error: result.error,
+      deliveredAt: new Date(),
+    };
+
+    this.deliveries.push(delivery);
+
+    if (result.success) {
+      this.logger.info(`Webhook delivered: ${delivery.id} (${result.statusCode})`);
+    } else {
+      this.logger.info(`Webhook delivery failed: ${delivery.id} — ${result.error}`);
+    }
+  }
+
+  /**
+   * Get all webhook deliveries.
+   */
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  /**
+   * Get deliveries for a specific webhook registration.
+   */
+  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.webhookId === webhookId);
+  }
+
+  /**
+   * Get the count of deliveries.
+   */
+  getDeliveryCount(): number {
+    return this.deliveries.length;
+  }
+
+  /**
+   * Clear all registrations and deliveries (useful for testing).
+   */
+  clear(): void {
+    this.registrations = [];
+    this.deliveries = [];
+  }
+}

