+    it('should track failed deliveries', async () => {
+      mockHttpPost = vi.fn().mockResolvedValue({ success: false, statusCode: 500, error: 'Server Error' });
+      handler = new WebhookNotificationHandler(eventBus, mockHttpPost);
+      handler.register('https://example.com/hook', 'order:created');
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const deliveries = handler.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]?.success).toBe(false);
+      expect(deliveries[0]?.statusCode).toBe(500);
+      expect(deliveries[0]?.error).toBe('Server Error');
