/**
 * Webhook notification handler — dispatches HTTP callbacks
 * when order events occur.
 *
 * Integrates with the EventBus pattern used throughout the application.
 * Subscribes to order lifecycle events and fires registered webhooks.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, AppEvent, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export interface WebhookPayload {
  eventType: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type HttpPostFn = (url: string, payload: WebhookPayload, secret?: string) => Promise<{ success: boolean; statusCode?: number; error?: string }>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

/**
 * Default HTTP post function — in-memory stub for demo purposes.
 * In production, this would use fetch/axios to make real HTTP calls.
 */
const defaultHttpPost: HttpPostFn = async () => {
  return { success: true, statusCode: 200 };
};

export class WebhookNotificationHandler {
  private logger = new Logger('WebhookNotificationHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private httpPost: HttpPostFn;

  constructor(private eventBus: EventBus, httpPost?: HttpPostFn) {
    this.httpPost = httpPost ?? defaultHttpPost;
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.dispatchWebhooks(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.dispatchWebhooks(event);
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  register(url: string, eventType: EventType, secret?: string): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      secret,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregister(webhookId: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === webhookId);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${webhookId}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Dispatch webhooks for a given event to all matching registrations.
   */
  private async dispatchWebhooks(event: AppEvent): Promise<void> {
    const matching = this.registrations.filter((r) => r.eventType === event.type);

    if (matching.length === 0) {
      return;
    }

    const payload = this.buildPayload(event);

    for (const registration of matching) {
      await this.deliverWebhook(registration, payload);
    }
  }

  private buildPayload(event: AppEvent): WebhookPayload {
    const base = {
      eventType: event.type,
      timestamp: event.timestamp.toISOString(),
    };

    switch (event.type) {
      case 'order:created':
        return {
          ...base,
          data: {
            order: event.order,
            user: { id: event.user.id, name: event.user.name, email: event.user.email },
          },
        };
      case 'order:status-changed':
        return {
          ...base,
          data: {
            order: event.order,
            previousStatus: event.previousStatus,
            newStatus: event.newStatus,
          },
        };
      default:
        return { ...base, data: {} };
    }
  }

  private async deliverWebhook(registration: WebhookRegistration, payload: WebhookPayload): Promise<void> {
    this.logger.info(`Delivering webhook ${registration.id} to ${registration.url}`);

    const result = await this.httpPost(registration.url, payload, registration.secret);

    const delivery: WebhookDelivery = {
      id: generateDeliveryId(),
      webhookId: registration.id,
      url: registration.url,
      eventType: payload.eventType,
      payload,
      success: result.success,
      statusCode: result.statusCode,
      error: result.error,
      deliveredAt: new Date(),
    };

    this.deliveries.push(delivery);

    if (result.success) {
      this.logger.info(`Webhook delivered: ${delivery.id} (${result.statusCode})`);
    } else {
      this.logger.info(`Webhook delivery failed: ${delivery.id} — ${result.error}`);
    }
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook registration.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookNotificationHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook-notification-handler.js';
import type { HttpPostFn } from '../../src/notifications/webhook-notification-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('WebhookNotificationHandler', () => {
  let eventBus: EventBus;
  let mockHttpPost: HttpPostFn;
  let handler: WebhookNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    mockHttpPost = vi.fn().mockResolvedValue({ success: true, statusCode: 200 });
    handler = new WebhookNotificationHandler(eventBus, mockHttpPost);
    resetWebhookIdCounters();
  });

  describe('webhook registration', () => {
    it('should register a webhook for an event type', () => {
      const reg = handler.register('https://example.com/hook', 'order:created');

      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.id).toBeDefined();
      expect(handler.getRegistrations()).toHaveLength(1);
    });

    it('should register multiple webhooks for different event types', () => {
      handler.register('https://example.com/created', 'order:created');
      handler.register('https://example.com/status', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(1);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should register multiple webhooks for the same event type', () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
    });

    it('should register a webhook with a secret', () => {
      const reg = handler.register('https://example.com/hook', 'order:created', 'my-secret');

      expect(reg.secret).toBe('my-secret');
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.register('https://example.com/hook', 'order:created');

      expect(handler.unregister(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregister('webhook-9999')).toBe(false);
    });
  });

  describe('webhook delivery on order:created', () => {
    it('should fire webhook when order:created event is emitted', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockHttpPost).toHaveBeenCalledTimes(1);
      const [url, payload] = (mockHttpPost as ReturnType<typeof vi.fn>).mock.calls[0]!;
      expect(url).toBe('https://example.com/hook');
      expect(payload.eventType).toBe('order:created');
      expect(payload.data.order.id).toBe('order-1');
      expect(payload.data.user.email).toBe('alice@example.com');
    });

    it('should fire multiple webhooks for the same event', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockHttpPost).toHaveBeenCalledTimes(2);
    });

    it('should not fire webhooks registered for different event types', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockHttpPost).not.toHaveBeenCalled();
    });

    it('should include order and user data in payload', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const [, payload] = (mockHttpPost as ReturnType<typeof vi.fn>).mock.calls[0]!;
      expect(payload.data.order).toBeDefined();
      expect(payload.data.user).toBeDefined();
      expect(payload.data.user.name).toBe('Alice');
      expect(payload.timestamp).toBe('2026-01-01T00:00:00.000Z');
    });

    it('should pass secret to httpPost', async () => {
      handler.register('https://example.com/hook', 'order:created', 'secret-123');

      await eventBus.emit(makeOrderCreatedEvent());

      const [, , secret] = (mockHttpPost as ReturnType<typeof vi.fn>).mock.calls[0]!;
      expect(secret).toBe('secret-123');
    });
  });

  describe('webhook delivery on order:status-changed', () => {
    it('should fire webhook when order:status-changed event is emitted', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      expect(mockHttpPost).toHaveBeenCalledTimes(1);
      const [url, payload] = (mockHttpPost as ReturnType<typeof vi.fn>).mock.calls[0]!;
      expect(url).toBe('https://example.com/hook');
      expect(payload.eventType).toBe('order:status-changed');
      expect(payload.data.previousStatus).toBe('pending');
      expect(payload.data.newStatus).toBe('confirmed');
    });

    it('should include order data in status change payload', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      const [, payload] = (mockHttpPost as ReturnType<typeof vi.fn>).mock.calls[0]!;
      expect(payload.data.order.id).toBe('order-1');
    });
  });

  describe('delivery tracking', () => {
    it('should track successful deliveries', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
    });

    it('should track failed deliveries', async () => {
      mockHttpPost = vi.fn().mockResolvedValue({ success: false, statusCode: 500, error: 'Server Error' });
      handler = new WebhookNotificationHandler(eventBus, mockHttpPost);
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(500);
      expect(deliveries[0]?.error).toBe('Server Error');
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const filtered = handler.getDeliveriesForWebhook(reg1.id);
      expect(filtered).toHaveLength(1);
      expect(filtered[0]?.url).toBe('https://a.com/hook');
    });

    it('should report delivery count', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      expect(handler.getDeliveryCount()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveryCount()).toBe(2);
    });

    it('should clear registrations and deliveries', async () => {
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('no registrations', () => {
    it('should not call httpPost when no webhooks are registered', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockHttpPost).not.toHaveBeenCalled();
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });
});
